import{c as t,Q as o,j as d,m as a}from"./chunks/framework.Bhbi9jCp.js";const h=JSON.parse('{"title":"Android 原生开发系列写作计划","description":"","frontmatter":{},"headers":[],"relativePath":"androidNativeLearning/00-写作计划.md","filePath":"androidNativeLearning/00-写作计划.md","lastUpdated":1779613419000}'),n={name:"androidNativeLearning/00-写作计划.md"};function r(i,e,s,c,l,p){return o(),d("div",null,[...e[0]||(e[0]=[a(`<h1 id="android-原生开发系列写作计划" tabindex="-1">Android 原生开发系列写作计划 <a class="header-anchor" href="#android-原生开发系列写作计划" aria-label="Permalink to &quot;Android 原生开发系列写作计划&quot;">​</a></h1><blockquote><p>来源:<code>未来系列规划.md</code> 第六类「平台原生开发」O. androidNative,⭐⭐⭐。 本系列基线版本为 <strong>Android 15 (API 35) / Kotlin 2.0 (K2 compiler) / Jetpack Compose BOM 1.7+</strong>(以 2026/05 时点为参照),聚焦 <strong>现代 Android 原生工程化</strong>:用工程师视角理解协程与 Flow、Compose 重组与状态、单 Activity 路由、Hilt 依赖注入、Room / DataStore、系统能力、多模块构建、性能基线、Play Store 发布通路。 本系列不做&quot;照抄某个 App&quot;的保姆级复刻,而是围绕一个可持续演进的 Kotlin + Compose 原型应用,逐层拆解 Android 从可运行到可维护、从可维护到可发布的关键机制。</p></blockquote><hr><h2 id="核心定位" tabindex="-1">核心定位 <a class="header-anchor" href="#核心定位" aria-label="Permalink to &quot;核心定位&quot;">​</a></h2><p>这不是&quot;Android 全家桶百科&quot;,也不是&quot;Java 老 Android 迁移到 Kotlin 手册&quot;,更不是&quot;Flutter / RN 跨端对比&quot;。本系列只解决一个明确目标:</p><blockquote><p>让一个熟悉编程但不熟悉 Android 平台的人,能用 <strong>Kotlin + Jetpack Compose + Android 15 (API 35)</strong> 做出一款架构清晰、状态可控、性能可量化、能上 Play Store 的现代 Android 应用。</p></blockquote><h3 id="读者画像" tabindex="-1">读者画像 <a class="header-anchor" href="#读者画像" aria-label="Permalink to &quot;读者画像&quot;">​</a></h3><ul><li>已掌握至少一门主流后端 / 前端语言,理解面向对象与函数式;</li><li>没怎么写过 Android,或者最后一次写 Android 还停在 Java + XML View + AsyncTask 时代;</li><li>想用 Kotlin 协程、Compose、Jetpack 全家桶把单端原生写好,而不是再绕一圈跨端;</li><li>终极交付目标:一款能签名、能上架、能灰度的 Android 应用,而不是 30 个独立 demo。</li></ul><h3 id="默认选择" tabindex="-1">默认选择 <a class="header-anchor" href="#默认选择" aria-label="Permalink to &quot;默认选择&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>选择</th><th>原因</th></tr></thead><tbody><tr><td>Android 版本</td><td>targetSdk = 35 (Android 15) / minSdk = 26 (Android 8.0)</td><td>覆盖 95%+ 设备,同时拥抱 Compose 与前台服务 type 强制</td></tr><tr><td>主语言</td><td>Kotlin 2.0,K2 Compiler 默认</td><td>协程 / Flow 一等公民;K2 编译速度与 Compose Compiler 集成</td></tr><tr><td>UI 框架</td><td>Jetpack Compose BOM 1.7+(Material 3)</td><td>不写 XML View;Shared Element / TextField2 / Lookahead 已稳定</td></tr><tr><td>Activity 模型</td><td>单 Activity + Navigation Compose</td><td>抛弃多 Activity / Fragment 心智</td></tr><tr><td>DI</td><td>Hilt(主选)+ Koin(对比一篇)</td><td>注解处理 + KSP 编译期生成</td></tr><tr><td>持久化</td><td>Room + DataStore</td><td>关系数据用 Room;键值 / Preferences 用 DataStore</td></tr><tr><td>网络</td><td>Retrofit + OkHttp + kotlinx.serialization</td><td>协程 <code>suspend</code> 一等公民,不写 RxJava</td></tr><tr><td>并发</td><td>Coroutines / StructuredConcurrency / Flow</td><td><code>viewModelScope</code> / <code>lifecycleScope</code> / 取消传播</td></tr><tr><td>构建</td><td>Gradle KTS + Version Catalogs (<code>libs.versions.toml</code>) + KSP</td><td>不写 Groovy;不写 KAPT(过渡到 KSP / KSP2)</td></tr><tr><td>性能</td><td>Macrobenchmark + Baseline Profiles</td><td>startup / scroll / frozen frames 可量化</td></tr><tr><td>测试</td><td>JUnit 4/5 + Compose UI Test + Robolectric</td><td>UI 与逻辑分层</td></tr><tr><td>发布</td><td>Play Console / App Bundle (AAB) / Play Integrity</td><td>不讲 APK 直接分发</td></tr><tr><td><strong>不覆盖</strong></td><td>KMP / Java 主线 / XML View 主线 / Flutter / React Native / NDK 深度</td><td>KMP 与跨端由 flutterLearning 覆盖;Java 与 XML 仅在「互操作」单篇出现</td></tr></tbody></table><blockquote><p>与 flutterLearning 的边界:flutter 讲跨端表现层与 Dart 语言;androidNative 讲 Kotlin 语言、Compose 重组与状态、Android 平台生命周期与系统能力、Gradle 构建与 Play 发布。两个系列读完应当能回答:&quot;为什么这件事一端原生做更快 / 跨端做更省&quot;。</p></blockquote><hr><h2 id="android-15-kotlin-2-0-compose-1-7-关键变更与本系列定位" tabindex="-1">Android 15 / Kotlin 2.0 / Compose 1.7 关键变更与本系列定位 <a class="header-anchor" href="#android-15-kotlin-2-0-compose-1-7-关键变更与本系列定位" aria-label="Permalink to &quot;Android 15 / Kotlin 2.0 / Compose 1.7 关键变更与本系列定位&quot;">​</a></h2><p>Android 15 (API 35) 自 2024-10 进入 stable,Kotlin 2.0 自 2024-05 发布并默认启用 K2,Compose BOM 1.7 自 2024-09 起为稳定主线。截至 2026/05,这三个版本已成为生产主流栈。本系列把下列变更显式纳入相关篇目,避免读者把 Android 13 / 14 / Kotlin 1.9 / Compose 1.5 时代心智带进来:</p><table tabindex="0"><thead><tr><th>变更</th><th>影响范围</th><th>本系列在哪篇展开</th></tr></thead><tbody><tr><td><strong>Edge-to-edge enforcement(targetSdk 35 强制)</strong></td><td>App 默认无 system bar 留白,需要主动处理 <code>WindowInsets</code> 与 <code>Scaffold</code> 内边距</td><td>第 06 / 09 篇</td></tr><tr><td><strong>16 KB page size 兼容</strong></td><td>第三方 <code>.so</code> 库需重对齐,影响 JNI / 含 native 的 SDK</td><td>第 26 / 28 篇</td></tr><tr><td><strong>Foreground Service Type Enforcement 加强</strong></td><td>启动前台服务必须声明 type 且匹配权限;后台拉起前台服务限制更严</td><td>第 17 篇</td></tr><tr><td><strong>Predictive Back Gesture 全量</strong></td><td>Activity / Compose Navigation 需正确实现 <code>OnBackPressedCallback</code> / <code>PredictiveBackHandler</code></td><td>第 12 篇</td></tr><tr><td><strong>Partial Screen Sharing API</strong></td><td><code>MediaProjection</code> 支持单 App 录屏</td><td>第 19 / 20 篇延伸提及</td></tr><tr><td><strong>Per-app language preferences 默认可用 (≥13)</strong></td><td>系统设置直接切换 App 语言,需 <code>LocaleConfig</code></td><td>第 27 篇</td></tr><tr><td><strong>Kotlin 2.0 K2 Compiler 默认</strong></td><td>编译速度↑,新泛型推断,smart cast 范围扩大,带来若干迁移坑</td><td>第 03 / 04 篇</td></tr><tr><td><strong>Compose Compiler 与 Kotlin 同版本发布(自 2.0.20 起内嵌)</strong></td><td>不再独立追 Compose Compiler 版本号</td><td>第 02 篇构建一节</td></tr><tr><td><strong>Compose 1.7 Strong Skipping 默认</strong></td><td>没有 <code>@Stable</code> 注解的类也会跳过重组,显著降低重组成本但会暴露不稳定 lambda</td><td>第 07 / 22 篇</td></tr><tr><td><strong>Compose 1.7 Shared Element Transition GA</strong></td><td><code>SharedTransitionLayout</code> / <code>sharedBoundsTransform</code> / <code>Modifier.sharedElement</code></td><td>第 10 篇</td></tr><tr><td><strong>Compose 1.7 <code>BasicTextField</code> (TextField2) 取代旧 TextField</strong></td><td><code>TextFieldState</code> hoist,输入法、IME、组合文本统一</td><td>第 08 篇</td></tr><tr><td><strong>Compose 1.7 LookaheadScope GA</strong></td><td>预测布局,实现&quot;列表展开 / 抽屉 / 共享元素&quot;自然过渡</td><td>第 10 / 22 篇</td></tr><tr><td><strong>KSP2 取代 KAPT</strong></td><td>Hilt / Room / Moshi / Glide 走 KSP,显著缩短增量构建</td><td>第 02 / 13 / 14 篇</td></tr><tr><td><strong>Navigation Compose 2.8+ 类型安全路由</strong></td><td>用 <code>@Serializable</code> data class 直接当路由,告别字符串模板</td><td>第 12 篇</td></tr><tr><td><strong>Play Integrity 取代 SafetyNet Attestation(2024 已完成下线)</strong></td><td>反作弊 / 反外挂 / 反越狱新接口</td><td>第 29 篇</td></tr></tbody></table><blockquote><p>说明:若在写稿时点已有 Android 16 (API 36) 进入稳定 / Compose 1.8 / 1.9 发布,会在受影响篇目补充 16 KB page size 强制启用、Privacy Sandbox 行为变化、新的预测式动画 API 等内容,并在篇首标注 &quot;本篇基于 BOM 1.7,1.8 差异补充见末尾&quot;。基线仍以 API 35 / Kotlin 2.0 / Compose 1.7 为主参考,避免文章漂移。</p></blockquote><hr><h2 id="六层路线" tabindex="-1">六层路线 <a class="header-anchor" href="#六层路线" aria-label="Permalink to &quot;六层路线&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Kotlin 心智与项目骨架</span></span>
<span class="line"><span>   → Jetpack Compose 声明式 UI 与状态心智</span></span>
<span class="line"><span>   → 数据、导航、依赖注入与第一个完整闭环</span></span>
<span class="line"><span>   → 系统能力:权限、相机、媒体、推送、后台</span></span>
<span class="line"><span>   → 多模块、性能、Baseline Profile 与启动优化</span></span>
<span class="line"><span>   → 测试、签名、上架与 Play 生态</span></span></code></pre></div><p>核心节奏是:<strong>前 15 篇先做出一个能跑、能展示数据、能登录的 Compose 应用,后 15 篇再把它接系统能力、做性能、上 Play Store。</strong></p><hr><h2 id="篇目设计-30-篇" tabindex="-1">篇目设计 (30 篇) <a class="header-anchor" href="#篇目设计-30-篇" aria-label="Permalink to &quot;篇目设计 (30 篇)&quot;">​</a></h2><h3 id="第一层-kotlin-心智与项目骨架-01-05" tabindex="-1">第一层:Kotlin 心智与项目骨架 (01-05) <a class="header-anchor" href="#第一层-kotlin-心智与项目骨架-01-05" aria-label="Permalink to &quot;第一层:Kotlin 心智与项目骨架 (01-05)&quot;">​</a></h3><ul><li><strong>01 现代 Android 心智总览</strong> (为什么 Kotlin + Compose + 单 Activity / Jetpack 全家桶定位 / minSdk 与 targetSdk 取舍 / 本系列最终交付什么应用)</li><li><strong>02 项目骨架与构建工具链</strong> (Android Studio Koala+ / <code>Gradle KTS</code> / <code>libs.versions.toml</code> Version Catalog / AGP × Kotlin 版本对齐表 / KSP / KSP2 / Compose Compiler 内嵌于 Kotlin 2.0.20+)</li><li><strong>03 Kotlin 2.0 语言心智</strong> (空安全 / <code>sealed interface</code> / <code>data class</code> / <code>value class</code> / Scope Functions / Extension / Delegation / <code>@JvmStatic</code> <code>@JvmOverloads</code> 互操作边界 / <strong>K2 smart cast 新行为与迁移踩坑</strong>)</li><li><strong>04 协程与结构化并发</strong> (<code>CoroutineScope</code> / <code>Job</code> / <code>SupervisorJob</code> / <code>Dispatchers.IO/Default/Main</code> / <code>viewModelScope</code> / <code>lifecycleScope</code> / 取消传播 / <code>withContext</code> 切线程 / 异常处理 <code>CoroutineExceptionHandler</code>)</li><li><strong>05 Flow、StateFlow 与 SharedFlow</strong> (cold vs hot / <code>flow {}</code> / <code>stateIn</code> / <code>MutableStateFlow</code> / <code>SharedFlow</code> replay / 与 LiveData 边界 / Compose <code>collectAsStateWithLifecycle</code> 与生命周期感知收集)</li></ul><h3 id="第二层-jetpack-compose-声明式-ui-与状态心智-06-10" tabindex="-1">第二层:Jetpack Compose 声明式 UI 与状态心智 (06-10) <a class="header-anchor" href="#第二层-jetpack-compose-声明式-ui-与状态心智-06-10" aria-label="Permalink to &quot;第二层:Jetpack Compose 声明式 UI 与状态心智 (06-10)&quot;">​</a></h3><ul><li><strong>06 Compose 入口与单 Activity</strong> (<code>ComponentActivity</code> / <code>setContent {}</code> / <code>MaterialTheme</code> / <code>Scaffold</code> / <code>Modifier</code> 顺序 / <strong>Android 15 edge-to-edge 强制与 <code>WindowInsets</code> 正确处理</strong> / 状态栏 / 导航栏 / IME 内边距)</li><li><strong>07 重组、状态与 remember</strong> (<code>State&lt;T&gt;</code> / <code>remember</code> vs <code>rememberSaveable</code> / Snapshot 系统 / 重组范围 / <code>derivedStateOf</code> / <code>key()</code> / <strong>Compose 1.7 Strong Skipping 与不稳定 lambda 暴露的代价</strong>)</li><li><strong>08 输入控件、TextField2 与表单状态</strong> (<code>BasicTextField</code> (TextField2) / <code>TextFieldState</code> / <code>KeyboardOptions</code> / <code>ImeAction</code> / 表单校验心智 / 旧 <code>TextField</code> 状态丢失问题与迁移)</li><li><strong>09 布局、Modifier 与自适应</strong> (<code>Row</code> / <code>Column</code> / <code>Box</code> / <code>LazyColumn</code> / <code>LazyVerticalGrid</code> / <code>Modifier.padding</code> 顺序坑 / <code>Constraints</code> 心智 / <code>WindowSizeClass</code> 适配手机 / 折叠屏 / 平板)</li><li><strong>10 动画、Shared Element 与 LookaheadScope</strong> (<code>animate*AsState</code> / <code>AnimatedVisibility</code> / <code>updateTransition</code> / <strong>Compose 1.7 <code>SharedTransitionLayout</code> + <code>sharedBoundsTransform</code></strong> / <strong><code>LookaheadScope</code> 预测布局</strong> / 动画与重组成本边界)</li></ul><h3 id="第三层-数据、导航、依赖注入与第一个完整闭环-11-15" tabindex="-1">第三层:数据、导航、依赖注入与第一个完整闭环 (11-15) <a class="header-anchor" href="#第三层-数据、导航、依赖注入与第一个完整闭环-11-15" aria-label="Permalink to &quot;第三层:数据、导航、依赖注入与第一个完整闭环 (11-15)&quot;">​</a></h3><blockquote><p>本层每篇做&quot;最小可行&quot;实现,目标是跑通&quot;启动 → 列表 → 详情 → 登录 → 本地缓存 → 远程同步&quot;闭环;系统能力放到第 16-20。</p></blockquote><ul><li><strong>11 应用架构:ViewModel、UDF 与 UI State</strong> (<code>ViewModel</code> / <code>SavedStateHandle</code> / 单向数据流 <code>UiState</code> / Action / Event 通道 / <code>MutableStateFlow</code> 暴露不可变 <code>StateFlow</code> / 与 Compose <code>collectAsStateWithLifecycle</code> 桥接)</li><li><strong>12 Navigation Compose 与单 Activity 路由</strong> (<code>NavHost</code> / <code>composable</code> 路由 / <strong>Navigation 2.8+ 类型安全 <code>@Serializable</code> 路由</strong> / 深链 / 返回栈 / <code>popBackStack</code> / <code>SavedStateHandle</code> 跨屏共享 / <strong>Predictive Back Gesture 集成</strong>)</li><li><strong>13 Hilt 依赖注入</strong> (<code>@HiltAndroidApp</code> / <code>@AndroidEntryPoint</code> / <code>@Inject</code> / <code>@Module</code> <code>@Provides</code> <code>@Binds</code> / <code>@HiltViewModel</code> / <code>SingletonComponent</code> 与 <code>ViewModelComponent</code> Scope / <strong>Hilt 走 KSP</strong> / 末尾一节 Koin 对比与取舍,不展开 Koin API)</li></ul><blockquote><p>主线 80% 讲 Hilt 工程化;Koin 仅作末尾对比小节,不写完整 demo。</p></blockquote><ul><li><strong>14 Room 与 DataStore 持久化</strong> (<code>@Entity</code> / <code>@Dao</code> / <code>@Database</code> / Schema 迁移 / <code>Flow&lt;List&lt;T&gt;&gt;</code> 查询 / <strong>Room KSP 化</strong> / <code>DataStore&lt;Preferences&gt;</code> / Proto DataStore / 与 SharedPreferences 的边界 / EncryptedSharedPreferences 心智延伸)</li><li><strong>15 Retrofit + OkHttp + kotlinx.serialization 与第一个闭环</strong> (<code>@GET</code> / <code>suspend</code> 函数 / <code>Result&lt;T&gt;</code> 包装 / <code>Interceptor</code> / <code>Cache-Control</code> / Token 刷新拦截 / 把第 11-14 篇串成&quot;登录 → 列表 → 详情 → 离线缓存&quot;完整闭环)</li></ul><h3 id="第四层-系统能力——权限、媒体、推送、后台-16-20" tabindex="-1">第四层:系统能力——权限、媒体、推送、后台 (16-20) <a class="header-anchor" href="#第四层-系统能力——权限、媒体、推送、后台-16-20" aria-label="Permalink to &quot;第四层:系统能力——权限、媒体、推送、后台 (16-20)&quot;">​</a></h3><ul><li><strong>16 Android 权限模型与运行时申请</strong> (<code>AndroidManifest</code> 声明 / <code>ActivityResultContracts.RequestPermission</code> / 权限组 / <code>shouldShowRequestPermissionRationale</code> / Android 14+ 部分照片 / 视频访问 (<code>READ_MEDIA_VISUAL_USER_SELECTED</code>) / <code>POST_NOTIFICATIONS</code> 适配 / Health Connect 心智)</li><li><strong>17 后台任务:WorkManager 与 Foreground Service</strong> (<code>WorkManager</code> / <code>OneTimeWorkRequest</code> / <code>PeriodicWorkRequest</code> / <code>Constraints</code> / <code>setExpedited</code> / <strong>Android 15 Foreground Service Type 强制</strong> / <code>ForegroundServiceType</code> 与对应权限矩阵 / 后台拉起新限制)</li><li><strong>18 通知系统与推送通道</strong> (<code>NotificationChannel</code> / <code>NotificationCompat</code> / Notification Trampoline 限制 / <code>POST_NOTIFICATIONS</code> 运行时申请 / <strong>FCM 远程推送</strong>:<code>FirebaseMessagingService</code> / Data Message vs Notification Message / Topic / <strong>国内推送渠道边界</strong>:Play Services 在国内不可用,华为 HMS Push / 小米 / OPPO / vivo / 统一推送联盟 (UnifiedPush) 选型与适配心智,不展开各家 SDK)</li></ul><blockquote><p>主线讲&quot;通知模型 + Android 15 行为变更&quot;,FCM 与国内推送渠道分两段。不展开任意厂商 SDK 集成细节,但讲清&quot;为什么这些渠道存在与统一抽象的工程做法&quot;。</p></blockquote><ul><li><strong>19 CameraX、Photo Picker 与 MediaStore</strong> (<code>PreviewView</code> (Compose interop) / <code>ImageCapture</code> / <code>VideoCapture</code> / <code>ImageAnalysis</code> 三大 UseCase 心智 / <code>MediaStore</code> 写入 (<code>MediaStore.Images</code> / Scoped Storage) / <strong>Photo Picker</strong> 与选择性媒体访问 / <code>READ_MEDIA_VISUAL_USER_SELECTED</code> 部分访问 / 末尾延伸提及 ML Kit 与 <code>MediaProjection</code>,不展开)</li></ul><blockquote><p>主线锁定 CameraX 三件套 + MediaStore 写入 + Photo Picker。ML Kit 端侧由 [[aiLearning 边界]] 覆盖,只在末尾说明集成入口;<code>MediaProjection</code> 录屏放到第 20 篇延伸。</p></blockquote><ul><li><strong>20 系统集成:Intent、App Links 与 Glance Widget</strong> (<code>Intent.ACTION_VIEW</code> / <code>Activity Result API</code> (<code>ActivityResultContracts</code>) / <strong>App Links 域名验签</strong>(<code>assetlinks.json</code> / Digital Asset Links) / Share Sheet (<code>ACTION_SEND</code>) 仅作 Intent 一节 / <strong>Glance</strong> Compose-style Widget 入门:<code>GlanceAppWidget</code> / <code>GlanceModifier</code> / 与传统 RemoteViews 边界 / <strong>MediaProjection 录屏延伸提及</strong>,不展开 QSTile)</li></ul><blockquote><p>主线三件:Intent / App Links / Glance Widget。Share Sheet 并入 Intent 一段;Quick Settings Tile 不写(收益低、心智重);<code>MediaProjection</code> 仅在末尾 1-2 段提及 API 入口与场景。</p></blockquote><h3 id="第五层-多模块、性能、baseline-profile-与启动优化-21-25" tabindex="-1">第五层:多模块、性能、Baseline Profile 与启动优化 (21-25) <a class="header-anchor" href="#第五层-多模块、性能、baseline-profile-与启动优化-21-25" aria-label="Permalink to &quot;第五层:多模块、性能、Baseline Profile 与启动优化 (21-25)&quot;">​</a></h3><ul><li><strong>21 多模块化:<code>:app</code> / <code>:feature-*</code> / <code>:core-*</code> / <code>:data</code></strong> (按层 vs 按 feature 切分 / 模块依赖图 / <code>api</code> vs <code>implementation</code> / <code>convention plugin</code> 与 <code>build-logic</code> / Gradle Version Catalogs 跨模块共享 / 模块边界与 DI 注入点)</li><li><strong>22 Compose 性能:重组、稳定性、Strong Skipping 与 <code>@Stable</code></strong> (<code>Compose Compiler Metrics Report</code> / <code>@Immutable</code> <code>@Stable</code> 注解 / <code>key()</code> / <code>LazyColumn</code> item key / 列表稳定性 / 避免不稳定 lambda / <code>remember { mutableStateOf() }</code> 失效模式)</li><li><strong>23 Macrobenchmark 与 Baseline Profiles</strong> (<code>androidx.benchmark.macro</code> / <code>StartupBenchmarks</code> / <code>ScrollBenchmarks</code> / frozen frames 量化 / <code>BaselineProfileRule</code> 生成 profile / <code>androidx.profileinstaller</code> 接入 / Play Store 自动分发 Baseline Profile)</li><li><strong>24 R8、混淆与代码瘦身</strong> (R8 vs ProGuard / <code>minifyEnabled</code> / <code>shrinkResources</code> / <code>-keep</code> 规则 / <strong>Kotlin / Compose / Hilt / Room / Retrofit / kotlinx.serialization 的混淆坑</strong> / <code>mapping.txt</code> 上传 / Resource Shrinking)</li><li><strong>25 启动优化与稳定性观测</strong> (<strong>主线:启动优化</strong>:<code>App Startup</code> library / lazy <code>Initializer</code> / <code>SplashScreen API</code> / <code>Trace.beginSection</code> / Cold / Warm / Hot start 区分 / <strong>延伸:稳定性观测</strong>:StrictMode / <code>ApplicationExitInfo</code> / ANR 触发与判定 / Firebase Crashlytics 接入 / Play Vitals 指标读法)</li></ul><blockquote><p>文章按 60/40 分两段:启动优化是主线(给可运行 demo),稳定性观测是延伸(讲指标体系与接入点,不展开 Crashlytics 全量功能)。</p></blockquote><h3 id="第六层-测试、签名、上架与-play-生态-26-30" tabindex="-1">第六层:测试、签名、上架与 Play 生态 (26-30) <a class="header-anchor" href="#第六层-测试、签名、上架与-play-生态-26-30" aria-label="Permalink to &quot;第六层:测试、签名、上架与 Play 生态 (26-30)&quot;">​</a></h3><ul><li><strong>26 Compose 测试与依赖隔离</strong> (<code>createComposeRule()</code> / <code>onNodeWithTag</code> / <code>performClick</code> / <code>waitUntil</code> / <strong>Hilt 测试 <code>@HiltAndroidTest</code> + <code>@UninstallModules</code></strong> / Test Doubles 与 Fake Repository / Robolectric 与 Instrumented Test 选型)</li><li><strong>27 多语言、字体与可访问性</strong> (<code>stringResource</code> / locales / <strong>per-app language preferences (Android 13+)</strong> + <code>LocaleConfig</code> / Downloadable Fonts / Variable Fonts / <code>contentDescription</code> / <code>semantics {}</code> / TalkBack 验收清单)</li><li><strong>28 App Bundle、签名与上架</strong> (<code>AAB</code> / Play App Signing / Internal / Closed / Open / Production 通道 / <strong>灰度发布与 Staged Rollout</strong> / <code>versionCode</code> / <code>bundletool</code> 本地验证 / 16 KB 对齐自检)</li><li><strong>29 Play Integrity 与反作弊基础</strong> (Play Integrity API verdicts / Standard vs Classic / nonce 协议 / 与服务端校验集成 / <strong>SafetyNet Attestation 已退役</strong> / <code>Network Security Config</code> / 证书钉扎 (Pin Set) 边界)</li><li><strong>30 工程检查表、CI 与长期维护</strong> (GitHub Actions / Gradle Build Cache / Unit + UI + Macrobenchmark 三层 CI / Dependabot / Compose BOM 升级节奏 / <strong>发布前清单</strong>:权限审查 / 隐私政策 / Data Safety 表单 / 大屏适配 / API level 兼容矩阵 / R8 mapping 上传 / Baseline Profile 验证)</li></ul><hr><h2 id="贯穿项目" tabindex="-1">贯穿项目 <a class="header-anchor" href="#贯穿项目" aria-label="Permalink to &quot;贯穿项目&quot;">​</a></h2><p>全系列围绕同一个逐步演进的 Android 应用 <strong>NotedX</strong>(笔记 + 待办 + 图片附件 + 云同步)展开,不是每篇从零起个孤立 demo。<strong>例外:第 21 篇(多模块化重构)、第 23 篇(Macrobenchmark 独立模块)、第 29 篇(Play Integrity 服务端 verdict 校验) 为可选扩展篇,允许使用独立最小工程演示,不强制嵌入主线应用。</strong></p><table tabindex="0"><thead><tr><th>阶段</th><th>应用状态</th><th>验收标准</th></tr></thead><tbody><tr><td>01-05</td><td>空骨架 + Kotlin 基础脚手架</td><td>Gradle KTS / Version Catalog / Kotlin 2.0 K2 跑通,<code>Flow → State</code> 桥接示例可运行</td></tr><tr><td>06-10</td><td>静态 UI 原型</td><td>单 Activity / Compose 主题 / 列表 / 表单 / 动画 / Shared Element 演示完整</td></tr><tr><td>11-15</td><td>数据闭环 MVP</td><td>能登录、能列表、能详情、本地 Room 缓存、远程 Retrofit 接口互通</td></tr><tr><td>16-20</td><td>系统能力闭环</td><td>权限合规、能用相机 / Photo Picker、收到 FCM 推送、有 WorkManager 后台任务、有深链</td></tr><tr><td>21-25</td><td>工程化与性能</td><td>多模块结构 / Strong Skipping 干净 / Baseline Profile 启动 ↓ 20%+ / R8 包体优化</td></tr><tr><td>26-30</td><td>可发布版本</td><td>AAB 签名上架 Internal Track,有 CI,有 Crashlytics,Play Integrity verdict 联通后端</td></tr></tbody></table><hr><h2 id="与其他系列的边界" tabindex="-1">与其他系列的边界 <a class="header-anchor" href="#与其他系列的边界" aria-label="Permalink to &quot;与其他系列的边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>内容</th><th>已有系列</th><th>本系列</th></tr></thead><tbody><tr><td>Dart / Widget / 跨端状态管理</td><td>flutterLearning</td><td>不重复跨端心智;本系列只讲 Kotlin / Compose 一端的状态与重组</td></tr><tr><td>线程 / 调度 / 协程底层</td><td>osLearning</td><td>不重复线程与调度实现;只讲 <code>Dispatchers</code> / <code>viewModelScope</code> 的工程用法</td></tr><tr><td>HTTP / TLS / DNS / HTTP/2/3</td><td>networkLearning</td><td>不重复协议层;只讲 OkHttp 拦截器 / 缓存策略 / Token 刷新 / 弱网兜底</td></tr><tr><td>AI 模型与端侧推理</td><td>aiLearning / aiInfraLearning</td><td>不讲模型本身;只讲 CameraX + ML Kit / Gemini Nano (AICore) 的端侧集成边界</td></tr><tr><td>加密原语与 TLS 推导</td><td>securityLearning</td><td>不重复密码学;只讲 <code>EncryptedSharedPreferences</code> / 证书钉扎 / Play Integrity 在 Android 上的落地</td></tr><tr><td>设计模式</td><td>designPatternLearning</td><td>不重复模式定义;只讲 Repository / UDF / Hilt 在 Android 上的落地</td></tr><tr><td>分布式与微服务</td><td>systemDesign / distributedLearning</td><td>不讲后端;只讲移动端如何配合后端做&quot;离线优先 / 冲突合并 / 增量同步&quot;</td></tr><tr><td>Rust / Go 语法</td><td>rustLearning / goLearning</td><td>不讲语言本身;NDK / JNI 仅在第 24 / 28 篇 16 KB 对齐处短暂出现</td></tr><tr><td>向量、矩阵、概率</td><td>mathForCS</td><td>只讲 Compose 动画曲线插值与传感器数据滤波的工程用法</td></tr><tr><td>iOS 原生</td><td>iosNative(规划中)</td><td>与本系列并列对照,不在 Android 系列里讨论 SwiftUI</td></tr></tbody></table><hr><h2 id="单篇写作模板" tabindex="-1">单篇写作模板 <a class="header-anchor" href="#单篇写作模板" aria-label="Permalink to &quot;单篇写作模板&quot;">​</a></h2><p>每篇遵循固定结构,避免变成散点知识:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 机制定位</span></span>
<span class="line"><span>   - 这个机制在 Android 应用里解决什么核心问题</span></span>
<span class="line"><span>   - Java + XML / AsyncTask / RxJava / 多 Activity 时代的旧解法为什么会失控</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. Android 心智</span></span>
<span class="line"><span>   - 对应核心类、注解与生命周期作用域(ViewModel / Lifecycle / CoroutineScope)</span></span>
<span class="line"><span>   - 数据流方向(UI ← StateFlow ← Repository ← DataSource)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 工程实现</span></span>
<span class="line"><span>   - 30-120 行可运行 Kotlin (Compose) 代码</span></span>
<span class="line"><span>   - 协程作用域、\`@Composable\` 与 \`Modifier\`、注解、构建脚本(KTS)、Manifest 声明、Hilt Module 一并给出</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 调参与验收</span></span>
<span class="line"><span>   - 哪些参数直接影响重组次数 / 启动耗时 / 包体积 / 用户感知</span></span>
<span class="line"><span>   - 怎么用 Layout Inspector / Profiler / Macrobenchmark / \`adb shell dumpsys\` 验证完成</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 踩坑</span></span>
<span class="line"><span>   - Android 15 / Kotlin 2.0 / Compose 1.7 下的常见坑</span></span>
<span class="line"><span>   - 与旧版教程、旧 API、Java + XML 心智、Kotlin 1.x 行为的区别</span></span></code></pre></div><hr><h2 id="交付标准" tabindex="-1">交付标准 <a class="header-anchor" href="#交付标准" aria-label="Permalink to &quot;交付标准&quot;">​</a></h2><p>不是每篇都强制新建一个完整工程,而是维护一个贯穿式示例应用,在关键机制处提供最小复现。</p><table tabindex="0"><thead><tr><th>交付物</th><th>要求</th></tr></thead><tbody><tr><td>Markdown 正文</td><td>讲清机制、设计取舍、实现步骤、踩坑边界</td></tr><tr><td>示例应用</td><td><code>androidNativeLearning/demo/</code> 中维护同一个 Android 15 + Compose 1.7 + Kotlin 2.0 应用</td></tr><tr><td>代码风格</td><td>Kotlin 2.0 (K2) / 协程结构化 / Compose 单向数据流 / Hilt + KSP / 不用 KAPT / 不用 RxJava</td></tr><tr><td>构建配置</td><td><code>build.gradle.kts</code> + <code>settings.gradle.kts</code> + <code>libs.versions.toml</code> + <code>gradle.properties</code> 完整可复制</td></tr><tr><td>图解</td><td>每层至少 1 张机制图;关键篇补:Compose 重组流图 / StateFlow 数据流图 / Hilt 依赖图 / Gradle 多模块依赖图 / Activity &amp; ViewModel 生命周期对齐图</td></tr><tr><td>验收</td><td>每篇末尾给出手动验证步骤;关键篇补 Compose UI Test / Macrobenchmark / <code>adb shell</code> 命令(<code>am start-activity</code> / <code>dumpsys gfxinfo</code> / <code>bugreport</code>)</td></tr><tr><td>官方指针</td><td>标注核心类名 / 注解,如 <code>ComponentActivity</code>、<code>SavedStateHandle</code>、<code>HiltViewModel</code>、<code>@Composable</code>、<code>Modifier</code>、<code>CoroutineScope</code>、<code>Flow&lt;T&gt;</code>、<code>StateFlow&lt;T&gt;</code>、<code>WorkRequest</code>、<code>BaselineProfileRule</code>、<code>PlayIntegrityManager</code></td></tr></tbody></table><hr><h2 id="章节节奏" tabindex="-1">章节节奏 <a class="header-anchor" href="#章节节奏" aria-label="Permalink to &quot;章节节奏&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01-05 建心智:Kotlin 2.0 / 协程 / Flow / Gradle KTS / Android Studio 工作流</span></span>
<span class="line"><span>06-10 做 UI:Compose 重组心智 / Modifier / 表单 / 列表 / 动画 / Shared Element</span></span>
<span class="line"><span>11-15 做闭环:UDF / Navigation / Hilt / Room / DataStore / Retrofit,跑通&quot;登录-列表-详情-缓存&quot;</span></span>
<span class="line"><span>16-20 接系统:权限 / WorkManager / 前台服务 / FCM / CameraX / Photo Picker / 深链 / Glance Widget</span></span>
<span class="line"><span>21-25 做工程:多模块 / Compose Strong Skipping / Macrobenchmark / Baseline Profile / R8 / 启动优化</span></span>
<span class="line"><span>26-30 做发布:Compose Testing / 多语言 / App Bundle / Play Integrity / CI 与发布前检查表</span></span></code></pre></div>`,61)])])}const u=t(n,[["render",r]]);export{h as __pageData,u as default};
